        continue
    for f in files:
        if f.endswith('.ts') or f.endswith('.tsx'):
            try:
                with open(os.path.join(root, f)) as fp:
                    c = fp.read()
                if 'expo-linking' in c or 'Linking.' in c:
                    has_deep_links = True
                    break
            except:
                pass
    if has_deep_links:
        break
print(f"  {'PASS' if has_deep_links else 'FAIL'} deep_link_support")

